const ReportingPaymentsTotals = `-- name: ReportingPaymentsTotals :one
SELECT
    COUNT(*) FILTER (
        WHERE
            p.state = 'authorized'
    )::bigint AS authorized_count,
    COUNT(*) FILTER (
        WHERE
            p.state = 'captured'
    )::bigint AS captured_count,
    COUNT(*) FILTER (
        WHERE
            p.state = 'failed'
    )::bigint AS failed_count,
    COUNT(*) FILTER (
        WHERE
            p.state = 'refunded'
    )::bigint AS refunded_count,
    COALESCE(SUM(p.amount_minor) FILTER (
        WHERE
            p.state = 'captured'
    ), 0)::bigint AS captured_amount_minor,
    COALESCE(SUM(p.amount_minor) FILTER (
        WHERE
            p.state = 'authorized'
    ), 0)::bigint AS authorized_amount_minor,
    COALESCE(SUM(p.amount_minor) FILTER (
        WHERE
            p.state = 'failed'
    ), 0)::bigint AS failed_amount_minor,
    COALESCE(SUM(p.amount_minor) FILTER (
        WHERE
            p.state = 'refunded'
    ), 0)::bigint AS refunded_amount_minor
FROM payments p
INNER JOIN orders o ON o.id = p.order_id
WHERE
    o.organization_id = $1
    AND p.created_at >= $2::timestamptz
    AND p.created_at < $3::timestamptz
`

type ReportingPaymentsTotalsParams struct {
	OrganizationID uuid.UUID
	Column2        time.Time
	Column3        time.Time
}

type ReportingPaymentsTotalsRow struct {
	AuthorizedCount       int64
	CapturedCount         int64
	FailedCount           int64
	RefundedCount         int64
	CapturedAmountMinor   int64
	AuthorizedAmountMinor int64
	FailedAmountMinor     int64
	RefundedAmountMinor   int64
}

func (q *Queries) ReportingPaymentsTotals(ctx context.Context, arg ReportingPaymentsTotalsParams) (ReportingPaymentsTotalsRow, error) {
	row := q.db.QueryRow(ctx, ReportingPaymentsTotals, arg.OrganizationID, arg.Column2, arg.Column3)
	var i ReportingPaymentsTotalsRow
	err := row.Scan(
		&i.AuthorizedCount,
		&i.CapturedCount,
		&i.FailedCount,
		&i.RefundedCount,
		&i.CapturedAmountMinor,
		&i.AuthorizedAmountMinor,
		&i.FailedAmountMinor,
		&i.RefundedAmountMinor,
	)
	return i, err
}

